/**
 * VariationCheckPopover Component
 *
 * A high-visibility modal popover that orchestrates the variation check process between meters and SAS data.
 *
 * Features:
 * - Animated state transitions (Checking, No Variations, Variations Found, Error)
 * - Portal-based rendering to ensure overlay priority
 * - Detailed breakdown of machine variation counts
 * - Action buttons for retry, minimize, and confirmed submission
 *
 * @param isOpen - Whether the popover is currently visible
 * @param isChecking - Whether the background variation check process is active
 * @param hasVariations - Result of the check (null if not finished, boolean otherwise)
 * @param error - Error message string if the check failed
 * @param variationsData - Full payload of variation check results including machine details
 * @param onMinimize - Callback to collapse the popover and view full details instead
 * @param onSubmit - Callback to proceed with report submission despite variations
 * @param onRetry - Callback to restart the variation check process
 * @param onClose - Callback to discard results and close the popover
 * @param isLoading - Global loading state for action buttons
 */
import { useEffect, useState } from 'react';
import { createPortal } from 'react-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { AlertCircle, CheckCircle2, Loader2 } from 'lucide-react';
import { Button } from '@/components/shared/ui/button';
import type { VariationsCheckResponse } from '@/lib/hooks/collectionReport/useCollectionReportVariationCheck';

interface VariationCheckPopoverProps {
  isOpen: boolean;
  isChecking: boolean;
  hasVariations: boolean | null;
  error: string | null;
  variationsData: VariationsCheckResponse | null;
  onMinimize: () => void;
  onSubmit: () => void;
  onRetry: () => void;
  onClose: () => void;
  isLoading?: boolean;
  isPreCreating?: boolean;
  currentMeterMachineName?: string | null;
  meterCreationError?: string | null;
}

export function VariationCheckPopover({
  isOpen,
  isChecking,
  hasVariations,
  error,
  variationsData,
  onMinimize,
  onSubmit,
  onRetry,
  onClose,
  isLoading = false,
  isPreCreating = false,
  currentMeterMachineName = null,
  meterCreationError = null,
}: VariationCheckPopoverProps) {
  // ============================================================================
  // State & Hooks
  // ============================================================================
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted || !isOpen) return null;

  // ============================================================================
  // Computed
  // ============================================================================
  const machineWithVariationsCount =
    variationsData?.machines.filter(
      m => typeof m.variation === 'number' && m.variation !== 0
    ).length || 0;
  const totalMachinesCount = variationsData?.machines.length || 0;

  // ============================================================================
  // Render
  // ============================================================================
  return createPortal(
    <AnimatePresence>
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        exit={{ opacity: 0, scale: 0.95 }}
        transition={{ duration: 0.2 }}
        className="fixed inset-0 z-[100010] flex items-center justify-center bg-black/50 p-4"
        style={{ pointerEvents: 'auto' }}
        onPointerDownCapture={e => e.stopPropagation()}
        onMouseDownCapture={e => e.stopPropagation()}
      >
        <motion.div
          className="w-full max-w-md rounded-lg bg-white p-6 shadow-xl"
          initial={{ y: 20 }}
          animate={{ y: 0 }}
          exit={{ y: 20 }}
          onClick={e => e.stopPropagation()}
        >
          {/* Pre-Creating Meters State */}
          {isPreCreating && (
            <div className="flex flex-col items-center gap-4">
              <motion.div
                animate={{ rotate: 360 }}
                transition={{ duration: 2, repeat: Infinity, ease: 'linear' }}
              >
                <Loader2 className="h-12 w-12 text-blue-500" />
              </motion.div>
              <p className="text-center text-lg font-semibold text-gray-800">
                Creating Manual Meters for{' '}
                <span className="font-bold">
                  {currentMeterMachineName ?? 'Machine'}
                </span>
              </p>
              <p className="text-center text-sm text-gray-600">Please wait...</p>
            </div>
          )}

)}

{/* Meter Creation Error State */}
{!isPreCreating && meterCreationError && (
  <div className="flex flex-col items-center gap-4">
    <motion.div
      initial={{ scale: 0 }}
      animate={{ scale: 1 }}
      transition={{ delay: 0.1, type: 'spring', stiffness: 200 }}
    >
      <AlertCircle className="h-12 w-12 text-red-500" />
    </motion.div>
    <div className="text-center">
      <p className="text-lg font-semibold text-gray-800">
        Failed to create meters
      </p>
      <p className="text-sm text-gray-600">
        Could not create meters for{' '}
        <strong>{currentMeterMachineName ?? 'Machine'}</strong>:{' '}
        {meterCreationError}
      </p>
    </div>
    <div className="flex gap-2 pt-2">
      <Button variant="outline" onClick={onClose} className="flex-1">
        Close
      </Button>
    </div>
  </div>
)}

{/* Checking State */}
{!isPreCreating && !meterCreationError && isChecking && (
  <div className="flex flex-col items-center gap-4">
    <motion.div
      animate={{ rotate: 360 }}
      transition={{ duration: 2, repeat: Infinity, ease: 'linear' }}
    >
      <Loader2 className="h-12 w-12 text-blue-500" />
    </motion.div>
    <p className="text-center text-lg font-semibold text-gray-800">
      Checking for variations...
    </p>
    <p className="text-center text-sm text-gray-600">
      Please wait while we analyze the data
    </p>
  </div>
)}

{/* No Variations State */}
{!isPreCreating && !meterCreationError && !isChecking && hasVariations === false && !error && (
  <div className="flex flex-col items-center gap-4">
    <motion.div
      initial={{ scale: 0 }}
      animate={{ scale: 1 }}
      transition={{ delay: 0.1, type: 'spring', stiffness: 200 }}
    >
      <CheckCircle2 className="h-12 w-12 text-green-500" />
    </motion.div>
    <div className="text-center">
      <p className="text-lg font-semibold text-gray-800">

