1	/**
2	 * POST /api/collection-reports/check-variations
3	 *
4	 * Compares meter gross against SAS gross for a set of machines to detect discrepancies
5	 * before a collection report is submitted. Developer/admin only maintenance route.
6	 *
7	 * Body fields:
8	 * @param {string} locationId - Required. ID of the gaming location; used to look up the licencee's `includeJackpot` setting.
9	 * @param {Array} machines - Required. Array of machine meter snapshots to check. Each entry must include:
10	 *   - `machineId`        {string}   Required. Machine identifier.
11	 *   - `metersIn`         {number}   Required. Current coin-in meter reading.
12	 *   - `metersOut`        {number}   Required. Current coin-out meter reading.
13	 *   - `machineName`      {string}   Optional. Display name; resolved from DB if omitted.
14	 *   - `sasStartTime`     {string}   Optional. ISO timestamp for the start of the SAS window.
15	 *   - `sasEndTime`       {string}   Optional. ISO timestamp for the end of the SAS window.
16	 *   - `prevMetersIn`     {number}   Optional. Previous coin-in reading used to calculate meter gross.
17	 *   - `prevMetersOut`    {number}   Optional. Previous coin-out reading used to calculate meter gross.
18	 *   - `movementGross`    {number}   Optional. Pre-calculated movement gross from a saved collection; overrides raw-meter calculation (ensures RAM-clear entries match report page).
19	 * @param {boolean} [includeJackpot] - Optional. When true, subtracts jackpot from SAS gross. Defaults to the licencee setting if omitted.
20	 */
21	
22	import type { NextRequest } from 'next/server';
23	import { connectDB } from '@/app/api/lib/middleware/db';
24	import {
25	  createSuccessResponse,
26	  createErrorResponse,
27	} from '@/app/api/lib/utils/apiResponse';
28	import { Machine } from '@/app/api/lib/models/machines';
29	import { GamingLocations } from '@/app/api/lib/models/gaminglocations';
30	import {
31	  logRouteCreate,
32	  logRouteError,
33	  extractUserFromRequest,
34	} from '@/app/api/lib/utils/routeLogger';
35	import type {
36	  GamingMachine,
37	  LicenceeDocument,
38	  MongooseId,
39	} from '@/shared/types';
40	import type { GamingLocationDocument } from '@/shared/types';
41	interface CheckVariationsRequest {
42	  locationId: string;
43	  machines: Array<{
44	    machineId: string;
45	    machineName?: string;
46	    metersIn: number;
47	    metersOut: number;
48	    sasStartTime?: string;
49	    sasEndTime?: string;
50	    prevMetersIn?: number;
51	    prevMetersOut?: number;
52	    /** Pre-calculated movement gross from a saved collection document.
53	     * When provided, used as meterGross instead of recalculating from raw meters.
54	     * Ensures RAM-clear entries match the report detail page calculation. */
55	    movementGross?: number;
56	  }>;
57	  includeJackpot?: boolean;
58	}
59	
60	interface MachineVariationData {
61	  machineId: string;
62	  machineName: string;
63	  variation: number | string;
64	  sasGross: number | string;
65	  meterGross: number;
66	  sasStartTime?: string | null;
67	  sasEndTime?: string | null;
68	}
69	
70	interface CheckVariationsResponse {
71	  hasVariations: boolean;
72	  totalVariation: number;
73	  machines: MachineVariationData[];
74	}
75	
76	/**
77	 * Main POST handler for checking collection report variations
78	 *
79	 * Compares meter gross against SAS gross for a set of machines to detect discrepancies
80	 * before a collection report is submitted. Developer/admin only maintenance route.
81	 *
82	 * @param {NextRequest} request - Information about the incoming request
83	 * @body {string} locationId - Required. ID of the gaming location; used to look up the licencee's `includeJackpot` setting.
84	 * @body {Array} machines - Required. Array of machine meter snapshots to check.
85	 *   - machineId {string} Required. Machine identifier.
86	 *   - metersIn {number} Required. Current coin-in meter reading.
87	 *   - metersOut {number} Required. Current coin-out meter reading.
88	 *   - machineName {string} Optional. Display name
89	 *   - sasStartTime {string} Optional. ISO timestamp for SAS window
90	 *   - sasEndTime {string} Optional. ISO timestamp for SAS window
91	 *   - prevMetersIn {number} Optional. Previous coin-in reading
92	 *   - prevMetersOut {number} Optional. Previous coin-out reading
93	 *   - movementGross {number} Optional. Pre-calculated gross
94	 * @body {boolean} includeJackpot - Optional. When true, subtracts jackpot from SAS gross. Defaults to the licencee setting if omitted.
95	 *
96	 * Flow:
97	 * 1. Connect to the database
98	 * 2. Parse request body and validate required fields
99	 * 3. Fetch licencee's includeJackpot flag if not provided
100	 * 4. Fetch machine details for display
101	 * 5. Fetch SAS meter data for machines with SAS time ranges
102	 * 6. Calculate variations (meter gross vs SAS gross) for each machine
103	 * 7. Return variation data and total variance
104	 */
105	export async function POST(request: NextRequest) {
106	  const startTime = Date.now();
107	  const functionName = 'POST /api/collection-reports/check-variations';
108	  const user = extractUserFromRequest(request);
109	
110	  try {
111	    // ============================================================================
112	    // STEP 1: Connect to the database
113	    // ============================================================================
114	    await connectDB();
115	
116	    // ============================================================================
117	    // STEP 2: Parse request body and validate required fields
118	    // ============================================================================
119	    const body = (await request.json()) as CheckVariationsRequest;
120	    const {
121	      locationId,
122	      machines,
123	      includeJackpot: userProvidedIncludeJackpot,
124	    } = body;
125	
126	    if (!locationId || !machines || machines.length === 0) {
127	      logRouteError(
128	        functionName,
129	        'POST',
130	        '/api/collection-reports/check-variations',
131	        'Invalid request: locationId and machines array required',
132	        user
133	      );
134	      return createErrorResponse(
135	        'Invalid request: locationId and machines array required',
136	        400,
137	        'INVALID_REQUEST'
138	      );
139	    }
140	
141	    // ============================================================================
142	    // STEP 3: Fetch licencee's includeJackpot flag if not provided
143	    // ============================================================================
144	    let includeJackpot = userProvidedIncludeJackpot ?? false;
145	    try {
146	      const location = await GamingLocations.findOne(
147	        { _id: locationId as unknown as MongooseId },
148	        { 'rel.licencee': 1 }
149	      ).lean<GamingLocationDocument>();
150	
151	      const licenceeId = location?.rel?.licencee;
152	      if (licenceeId) {
153	        const { Licencee } = await import('@/app/api/lib/models/licencee');
154	        const licenceeDoc = await Licencee.findOne(
155	          { _id: licenceeId },
156	          { includeJackpot: 1 }
157	        ).lean<LicenceeDocument>();
158	        includeJackpot = Boolean(licenceeDoc?.includeJackpot);
159	      }
160	    } catch (err) {
161	      console.warn(
162	        '[Collection Report] Could not fetch licencee includeJackpot:',
163	        err
164	      );
165	      // Continue with default value
166	    }
167	
168	    // ============================================================================
169	    // STEP 4: Fetch machine details for display
170	    // ============================================================================
171	    const machineIds = machines.map(
172	      machine => machine.machineId as unknown as MongooseId
173	    );
174	    const machineDetails = await Machine.find(
175	      { _id: { $in: machineIds } },
176	      {
177	        machineId: 1,
178	        serialNumber: 1,
179	        custom: 1,
180	        game: 1,
181	        machineCustomName: 1,
182	        machineName: 1,
183	        relayId: 1,
184	      }
185	    ).lean<GamingMachine[]>();
186	
187	    const machineDetailsMap = new Map(
188	      machineDetails.map(machineDetail => [machineDetail._id, machineDetail])
189	    );
190	
191	    // ============================================================================
192	    // STEP 5: Fetch SAS meter data for machines with SAS time ranges
193	    // ============================================================================
194	    const { Meters } = await import('@/app/api/lib/models/meters');
195	
196	    const meterQueries = machines
197	      .filter(machine => machine.sasStartTime && machine.sasEndTime)
198	      .map(machine => ({
199	        machineId: machine.machineId,
200	        startTime: new Date(machine.sasStartTime!),
201	        endTime: new Date(machine.sasEndTime!),
202	      }));
203	
204	    const allMeterData: Array<{
205	      _id: string;
206	      totalDrop: number;
207	      totalCancelled: number;
208	      totalJackpot: number;
209	    }> = [];
210	
