// ============================================================
// Phase 1: Pre-create meters for offline/non-SMIB machines
// ============================================================
if (preCreatePayloads.length > 0) {
  setState({
    ...DEFAULT_STATE,
    isPreCreating: true,
  });

  // Track whether any meter was actually written to DB so we can
  // guarantee the "Creating Manual Meters" message stays on screen
  // long enough for the user to read it (React renders are macro-tasks;
  // very fast local fetches complete as microtasks before the first
  // paint, so we enforce a minimum display duration after creation).
  const preCreateStartTime = Date.now();
  let anyMeterCreated = false;

  for (const payload of preCreatePayloads) {
    setState(prev => ({
      ...prev,
      currentMeterMachineName: payload.customName ?? 'Machine',
    }));

    try {
      const response = await fetch(
        '/api/collection-reports/pre-create-meters',
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            ...payload,
            sasEndTime:
              payload.sasEndTime instanceof Date
                ? payload.sasEndTime.toISOString()
                : payload.sasEndTime,
          }),
        }
      );

      const data = await response.json();

      if (!response.ok || !data.success) {
        const displayName =
          data.customName ?? payload.customName ?? 'Machine';
        setState(prev => ({
          ...prev,
          isPreCreating: false,
          currentMeterMachineName: displayName,
          meterCreationError:
            data.error ?? 'Failed to create meter documents',
        }));
        return;
      }

      if (data.created) {
        anyMeterCreated = true;
      }
    } catch (err) {
      setState(prev => ({
        ...prev,
        isPreCreating: false,
        meterCreationError:
          err instanceof Error ? err.message : 'Unknown error occurred',
      }));
      return;
    }
  }

  // If meters were created, hold the "Creating Manual Meters" message
  // on screen for at least 1 second so the user can see it.  This is
  // the explicit confirmation that the meter was created before the
  // variation check fires — online SMIB machines (skipped) get no delay.
  if (anyMeterCreated) {
    const elapsed = Date.now() - preCreateStartTime;
    const MIN_DISPLAY_MS = 1000;
    if (elapsed < MIN_DISPLAY_MS) {
      await new Promise<void>(resolve =>
        setTimeout(resolve, MIN_DISPLAY_MS - elapsed)
      );
    }
  }

  // All pre-creates confirmed — clear phase before handing off
  setState(prev => ({
    ...prev,
    isPreCreating: false,
    currentMeterMachineName: null,
  }));
}

